-- 2026-06-25: shoulder_oa — фазы «Путь» + структурированные критерии перехода.
-- Протокол: артроз плечевого (плечелопаточного, гленогумерального) сустава — КОНСЕРВАТИВНОЕ ведение.
--
-- Источник: PROTOCOLS/shoulder досье + proto_shoulder_oa.json (suggested_program_type_code='shoulder_oa',
-- anchor='criterion_driven', 3 фазы 1–3, БЕЗ phase 0 — операции нет, нет окна заживления).
-- Хирургия (анатомическое TSA / реверсивное RSA) НЕ выделена отдельным program_type, а ведётся как
-- ЭСКАЛАЦИЯ / красный флаг: при стойкой боли и ограничении, не отвечающих на адекватное консервативное
-- ведение ориентировочно 6–12 месяцев → обсуждение эндопротезирования с хирургом (это red_flag фазы 3,
-- а НЕ критерий перехода между фазами реабилитации).
--
-- Защитная ось: бережём дегенеративно изменённый сустав — никакого «через боль» и форсированной
-- конечной амплитуды; нагрузка дозируется, а не исключается. Артроз протекает волнообразно: обострения
-- ожидаемы и управляемы — временный откат к мягким упражнениям фазы 1, затем повторное наращивание
-- (это НЕ смена program_type). Прогрессия криериальная/функциональная, НЕ календарная: длительности
-- фаз даны лишь как ориентиры (Ф1: 1–3 нед, Ф2: 3–8 нед, Ф3: с 8-й недели и далее бессрочно).
--
-- Контент в ПАЦИЕНТСКОМ регистре (без клинич. жаргона PROM/AROM/ER/IR/scaption — раскрыт словами:
-- «пассивный подъём руки», «поворот руки наружу», «сила мышц манжеты и лопатки» и т.п.).
-- Vadim калибрует через AdminContent после деплоя.
--
-- criteria_next (free-text на rehab_phases) дублирует метки критериев → пациент видит их СРАЗУ
-- в «Пути». Структурированная phase_transition_criteria — для будущей авто-проверки (слот D2).
-- Фаза 3 — конечная (бессрочный режим поддержания), но ИМЕЕТ непустые transition_criteria в источнике
-- (критерии «цель достигнута / выход в поддержание», включая PASS) → критерии включены.
--
-- Классификация критериев (ТЗ §2.3): авто-проверяемо сегодня только боль ВАШ → criterion_type
-- 'measurement' (measurement_type='vas_score', source='pain' — единый код против pain_entries.vas_score,
-- как в ACL-seed 20260518). Числовых валидированных порогов перехода для артроза в литературе нет:
-- единственные числа — боль/ВАШ (≤4/10). Все ROM/сила/PROM-критерии (активное сгибание, шкалы
-- WOOS/SPADI/DASH/ASES) — 'instructor_check' БЕЗ порога с пометкой «решает куратор очно» (порог в тексте
-- label). Качественное да/нет от пациента → 'self_report'.
--
-- Идемпотентна: ON CONFLICT DO NOTHING для обеих таблиц (AdminContent = источник истины после
-- деплоя; ручная калибровка не затирается). Прогон тест-цикла createdb→schema→migrations×2 → ок.
-- НЕ трогает acl/knee/другие program_type (разные program_type/phase_id).

BEGIN;

-- =====================================================
-- 1. Фазы shoulder_oa (контент «Путь»)
-- =====================================================
INSERT INTO rehab_phases (program_type, phase_number, title, subtitle, duration_weeks, description, goals, restrictions, criteria_next, icon, color, color_bg, teaser, allowed, pain, daily, red_flags, faq)
VALUES
