    '[{"q":"Это навсегда?","a":"Поддерживающая программа — да, она надолго. Регулярные занятия 2–3 раза в неделю удерживают силу и подвижность и снижают частоту обострений. Это образ жизни, а не временный курс."},{"q":"Что делать при обострении?","a":"Обострения при артрозе ожидаемы и управляемы. Временно вернитесь к мягким упражнениям первой фазы, а когда станет легче — снова постепенно наращивайте нагрузку."},{"q":"А если станет хуже, несмотря на занятия?","a":"Если стойкая боль и ограничение не уходят при адекватном консервативном ведении ориентировочно за 6–12 месяцев, стоит обсудить с хирургом варианты, включая эндопротезирование. Это не неудача, а следующий разумный шаг."}]'
)
ON CONFLICT (program_type, phase_number) DO NOTHING;

-- =====================================================
-- 2. Структурированные критерии перехода shoulder_oa
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
--    Фазы 1–3 (терминальная фаза 3 несёт критерии достижения цели / выхода в поддержание).
--    measurement = боль ВАШ (vas_score+pain) ТОЛЬКО; объём/сила/PROM-шкалы → instructor_check.
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (контроль боли и защита сустава → восстановление подвижности)
  (1, 'rest_pain_reduced_p1',   'Острая боль покоя снизилась по сравнению с началом',                                          'self_report',      NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 7::smallint, 'Снизилась ли острая боль покоя по сравнению с началом — можете ли заниматься без резкой боли?', 'Сравните боль в покое сейчас и в начале занятий', 10::smallint, TRUE),
  (1, 'sleep_through_night_p1', 'Получается спать большую часть ночи без пробуждений от боли в плече',                          'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете ли спать большую часть ночи без пробуждений от боли в плече?', 'Оцените по нескольким последним ночам', 20::smallint, TRUE),
  (1, 'pain_exercise_le_4_p1',  'Боль во время базовых упражнений не более 4 из 10',                                           'measurement',      'vas_score', 'pain', '<=', 4::numeric, NULL, 7::smallint, NULL, NULL, 30::smallint, TRUE),
  (1, 'gentle_moves_no_guard_p1','Маятниковые и ассистированные движения и напряжения мышц без болезненной защитной реакции (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (1, 'home_program_learned_p1','Освоена и корректно демонстрируется домашняя программа и принципы бережного отношения к суставу (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, FALSE),

  -- Фаза 2 → Фаза 3 (восстановление подвижности → функциональная сила и самоведение)
  (2, 'active_flexion_adl_p2',  'Активный подъём руки вперёд достаточен для бытовых задач на уровне плеч (порога в градусах нет, решает куратор очно)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'pain_loaded_le_4_p2',    'Боль при нагрузочных упражнениях не более 4 из 10 и стихает к следующему дню',                 'measurement',      'vas_score', 'pain', '<=', 4::numeric, NULL, 7::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'adl_shoulder_level_p2',  'Повседневные дела на уровне плеч даются без существенной боли',                                'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете выполнять повседневные дела на уровне плеч (одеться, причесаться, достать предмет с полки) без существенной боли?', 'Оцените по реальным бытовым движениям на уровне плеч', 30::smallint, TRUE),
  (2, 'scapular_rhythm_ok_p2',  'Восстановлена слаженная работа плеча и лопатки, нет выраженной болезненной дуги при подъёме руки в сторону (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (2, 'tolerates_resistance_p2','Переносится постепенное сопротивление (лента, лёгкие веса) без обострения в течение суток (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, FALSE),

  -- Фаза 3 (терминальная) — критерии достижения цели / выхода в режим поддержания
  (3, 'pass_satisfied_p3',      'Состояние плеча устраивает для повседневной жизни (Patient Acceptable Symptom State)',          'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Удовлетворены ли вы текущим состоянием плеча для своей повседневной жизни?', 'Оцените в целом: достаточно ли плечо вас устраивает для обычной жизни', 10::smallint, TRUE),
  (3, 'self_manage_flares_p3',  'Получается самостоятельно справляться с обострениями домашней программой',                     'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете ли самостоятельно справляться с обострениями домашней программой?', 'На обострении вернуться к мягким упражнениям и затем снова наращивать', 20::smallint, TRUE),
  (3, 'maintenance_indep_p3',   'Поддерживающая программа выполняется самостоятельно и безопасно (подтверждает куратор)',        'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 30::smallint, TRUE),
  (3, 'outcome_score_stable_p3','Состояние по контрольной шкале (WOOS, SPADI, DASH или ASES) стабильно или улучшается — порог решает куратор очно', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 40::smallint, FALSE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'shoulder_oa' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
